module d_flip_flop_sync_reset (
    input clk,
    input reset,
    input d,
    output reg q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 0;
        else
            q <= d;
    end

endmodule
